import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { X, Loader2, CheckCircle, CreditCard, Wallet, Shield, ArrowRight } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import './WalletActions.css';

export default function AddFunds() {
  const navigate = useNavigate();
  const { t } = useTranslation();
  
  const [amount, setAmount] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('card');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [addedAmount, setAddedAmount] = useState(0);

  const quickAmounts = [100, 500, 1000, 2000];
  const paymentMethods = [
    { id: 'card', label: 'Credit/Debit Card', icon: CreditCard },
    { id: 'upi', label: 'UPI / GPay / Paytm', icon: Wallet },
    { id: 'netbanking', label: 'Net Banking', icon: Shield },
  ];

  // Close modal on Escape key
  useEffect(() => {
    const handleEsc = (e) => e.key === 'Escape' && navigate('/wallet');
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [navigate]);

  const handleAddFunds = async () => {
    setError('');
    const num = parseFloat(amount);
    if (!amount || isNaN(num) || num <= 0) return setError('Enter a valid amount');
    if (num < 10) return setError('Minimum amount is ₹10');
    if (!paymentMethod) return setError('Select a payment method');

    setLoading(true);
    try {
      // 🔥 Replace with Razorpay/Stripe API
      await new Promise(res => setTimeout(res, 1500));
      setAddedAmount(num);
      setSuccess(true);
    } catch {
      setError('Payment failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => navigate('/wallet');

  // ✅ SUCCESS STATE
  if (success) {
    return (
      <div className="wallet-modal-overlay" onClick={handleClose}>
        <div className="wallet-modal-card" onClick={e => e.stopPropagation()}>
          <button onClick={handleClose} className="modal-close-btn" aria-label="Close">
            <X size={20} />
          </button>
          <div className="success-content">
            <div className="success-icon"><CheckCircle size={48} /></div>
            <h3>₹{addedAmount.toFixed(2)} Added!</h3>
            <p className="success-msg">Your wallet has been credited successfully.</p>
            <div className="success-details">
              <div className="detail-row"><span>Method</span><strong>{paymentMethods.find(m => m.id === paymentMethod)?.label}</strong></div>
              <div className="detail-row"><span>Time</span><strong>{new Date().toLocaleTimeString()}</strong></div>
            </div>
            <div className="success-actions">
              <button className="primary-btn" onClick={() => navigate('/products')}>
                <span>Continue Shopping</span><ArrowRight size={18} />
              </button>
              <button className="secondary-btn" onClick={handleClose}>View Wallet Balance</button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ✅ FORM STATE
  return (
    <div className="wallet-modal-overlay" onClick={handleClose}>
      <div className="wallet-modal-card" onClick={e => e.stopPropagation()}>
        <button onClick={handleClose} className="modal-close-btn" aria-label="Close">
          <X size={20} />
        </button>
        <h2 className="modal-title">Add Money to Wallet</h2>
        
        <div className="modal-form">
          <div className="form-section">
            <label>Enter Amount</label>
            <div className="amount-input-wrap">
              <span className="currency-sym">₹</span>
              <input 
                type="number" 
                placeholder="0.00" 
                value={amount} 
                onChange={(e) => setAmount(e.target.value)} 
                min="10" 
                step="0.01" 
              />
            </div>
            <div className="quick-amounts">
              {quickAmounts.map(v => (
                <button 
                  key={v} 
                  type="button" 
                  onClick={() => setAmount(v.toString())} 
                  className={amount === v.toString() ? 'selected' : ''}
                >
                  ₹{v}
                </button>
              ))}
            </div>
            {error && <p className="error-msg" role="alert">{error}</p>}
          </div>

          <div className="form-section">
            <label>Payment Method</label>
            <div className="payment-methods">
              {paymentMethods.map(m => (
                <button 
                  key={m.id} 
                  type="button" 
                  onClick={() => setPaymentMethod(m.id)} 
                  className={paymentMethod === m.id ? 'selected' : ''}
                >
                  <m.icon size={18} /> 
                  <span>{m.label}</span>
                  {paymentMethod === m.id && <CheckCircle size={16} className="check-icon" />}
                </button>
              ))}
            </div>
          </div>

          {amount && parseFloat(amount) >= 10 && (
            <div className="summary-box">
              <div className="sum-row"><span>Convenience Fee</span><strong className="free">Free</strong></div>
              <div className="sum-row total"><span>Total Payable</span><strong>₹{parseFloat(amount).toFixed(2)}</strong></div>
            </div>
          )}

          <button 
            className="primary-btn" 
            onClick={handleAddFunds} 
            disabled={loading || !amount || parseFloat(amount) < 10}
          >
            {loading ? (
              <><Loader2 className="spin" size={18} /> Processing...</>
            ) : (
              <><span>Pay ₹{amount ? parseFloat(amount).toFixed(2) : '0.00'}</span><ArrowRight size={18} /></>
            )}
          </button>
        </div>
      </div>
    </div>
  );
}
